const orders = $('Fetch Recent Orders').all();
const salesMap = {};
for (const order of orders) {
  for (const item of (order.json.line_items || [])) {
    const vid = String(item.variant_id);
    salesMap[vid] = (salesMap[vid] || 0) + (item.quantity || 0);
  }
}
const products = $('Fetch All Products').all();
const result = [];
for (const product of products) {
  for (const variant of (product.json.variants || [])) {
    const vid = String(variant.id);
    const stock = variant.inventory_quantity || 0;
    const sold7d = salesMap[vid] || 0;
    const velocity = sold7d / 7;
    const days_until_stockout = velocity > 0 ? Math.floor(stock / velocity) : 999;
    result.push({ json: {
      product_title:    product.json.title,
      variant_id:       vid,
      variant_title:    variant.title,
      sku:              variant.sku || '',
      stock,
      sold_7d:          sold7d,
      velocity_per_day: Math.round(velocity * 100) / 100,
      days_until_stockout
    }});
  }
}
return result;

